export const CATEGORY_LABEL: Record<DiaCategory,string> = {
  weekday_day: '평일',
  holiday_day: '휴일',
  pp: '평-평',
  ph: '평-휴',
  hp: '휴-평',
  hh: '휴-휴',
  off: '비번',
};

// Extract first HH:MM from departure string e.g. "동06:43-진..." => "06:43"
export function extractDeparture(dep: string): string | undefined {
  const m = dep.match(/(\d{1,2}):?(\d{2})/);
  if (!m) return undefined;
  return `${m[1].padStart(2,'0')}:${m[2]}`;
}
